INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'The treatment of water with bleaching powder is known as', 'Super chlorination', 'Pre-chlorination', 'De-chlorination', 'Hypo-chlorination', 4, 'Bleaching powder is calcium hypochlorite, hence hypochlorination.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '64289b52-861b-4a49-9286-4c4196691af7'::uuid, '9b40396e-3ed0-47ab-b981-52f6a8e6cdd3'::uuid, 2023, 'Paper-I', 'A syphon aqueduct is provided when', 'the canal bed level lies between the bed level and HFL of the drain', 'the canal bed level is well below the flood level of the drain', 'the drain bed level is well below FSL of the canal', 'the canal bed level lies above the bed level and HFL of the drain', 2, 'Syphon aqueduct is used when canal bed is below drain HFL, so water flows under pressure.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '64289b52-861b-4a49-9286-4c4196691af7'::uuid, '9b40396e-3ed0-47ab-b981-52f6a8e6cdd3'::uuid, 2023, 'Paper-I', 'Which of the following is example for sub surface irrigation ?', 'Sprinkler irrigation', 'Drip irrigation', 'Flow irrigation', 'Furrow irrigation', 2, 'Drip irrigation delivers water below or near the surface, often considered sub-surface.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '637bf719-8dde-4035-946c-4242372328e2'::uuid, '29d611e8-8d9c-48f0-85c3-621cccd58722'::uuid, 2023, 'Paper-I', 'What is SSD in highway engineering ?', 'Stopping Signal Distance', 'Slow Sight Distance', 'Stopping Skid Distance', 'Stopping Sight Distance', 4, 'SSD stands for Stopping Sight Distance.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '637bf719-8dde-4035-946c-4242372328e2'::uuid, '29d611e8-8d9c-48f0-85c3-621cccd58722'::uuid, 2023, 'Paper-I', 'The expression for the length of tangent for simple circular curve is given by where R is radius, α is deflection angle.', '2R Sin α/2', 'R Tan α/2', '2R Tan α/2', 'R Sin α/2', 2, 'Tangent length = R tan(Δ/2).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'e7eaeaa0-d839-4490-abed-c71027b61424'::uuid, '1bba627d-75a7-47e9-8413-f09905572b33'::uuid, 2023, 'Paper-I', 'A short square column of sides 300 mm is reinforced with 4 numbers of 20 mm diameter bars. What is the ultimate load carrying capacity of the column considering minimum eccentricity less than 0.05 times the lateral dimensions ? Use M20 and Fe 415 as the grades of concrete and steel, respectively.', '20 mm', '20 cm', '21.10 cm', '21.30 mm', Unknown, 'Calculation gives load ~1059 kN, not matching options; question likely misprinted.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a8556419-0986-4502-80b2-78b7defb8990'::uuid, 'ec71764c-6040-47e0-bbc1-9777aafbeec7'::uuid, 2023, 'Paper-I', 'An open tank contains 1 m deep water with 50 cm depth of oil of specific gravity 0.8 above it. The intensity of pressure at the bottom of tank will be', '10 kN/m²', '4 kN/m²', '12 kN/m²', '14 kN/m²', 4, 'Pressure = 9.81×1 + 0.8×9.81×0.5 = 9.81 + 3.924 = 13.734 ≈ 14 kN/m².', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '64289b52-861b-4a49-9286-4c4196691af7'::uuid, '9b40396e-3ed0-47ab-b981-52f6a8e6cdd3'::uuid, 2023, 'Paper-I', 'Which of the following is NOT a canal head work ?', 'Aqueduct', 'Weir', 'Barrage', 'Head regulator', 1, 'Aqueduct is a cross drainage work, not a head work.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1'::uuid, '4c395c9a-2cad-4ea6-ac3d-b0b7bd1a4dee'::uuid, 2023, 'Paper-I', 'Water content of soil mass is defined as', 'Ratio of volume of water in voids to volume of voids', 'Ratio of weight of solids to the weight of water', 'Ratio of volume of voids to volume of water in voids', 'Ratio of weight of water to the weight of solids', 4, 'Water content = W_w / W_s.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Arrange the steps of preparation of brick earth in chronological order : A. unsolling B. cleaning C. digging D. blending E. weathering F. tempering', 'A, C, B, E, D, F', 'A, B, C, D, E, F', 'A, F, B, E, D, C', 'A, C, B, D, E, F', 1, 'Unsolling → Digging → Cleaning → Weathering → Blending → Tempering.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'dd2eab18-a6c2-4636-a005-1f9ea9aef419'::uuid, '4002ff85-6eee-4cd3-8c35-1d7039df2745'::uuid, 2023, 'Paper-I', 'What is the maximum bending moment of a simply supported beam of length L loaded with a uniformly distributed load w per unit length over one half of the span ?', '3wL²/128', 'wL²/8', '9wL²/64', '9wL²/128', 4, 'Mmax = 9wL²/128 (derived from shear force zero at x=3L/8).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a8556419-0986-4502-80b2-78b7defb8990'::uuid, 'ec71764c-6040-47e0-bbc1-9777aafbeec7'::uuid, 2023, 'Paper-I', 'Identify the correct relation among coefficient of discharge (C_d), coefficient of velocity (C_v) and coefficient of contraction (C_c).', 'C_c = C_v + C_d', 'C_v = C_d * C_c', 'C_d = C_c * C_v', 'C_d = C_c + C_v', 3, 'C_d = C_c × C_v.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'dd2eab18-a6c2-4636-a005-1f9ea9aef419'::uuid, '4002ff85-6eee-4cd3-8c35-1d7039df2745'::uuid, 2023, 'Paper-I', 'Consider two forces in a cartesian x-y coordinate system. Match the following for the forces: A. Collinear forces B. Coplanar forces C. Concurrent forces D. Coplanar non-concurrent forces', 'A-1, B-2, C-4, D-3', 'A-3, B-4, C-1, D-2', 'A-4, B-3, C-1, D-2', 'A-4, B-3, C-2, D-1', 3, 'Collinear - same line (4); Coplanar - same plane (3); Concurrent - meet at point (1); Coplanar non-concurrent - same plane, not meet (2).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '637bf719-8dde-4035-946c-4242372328e2'::uuid, '29d611e8-8d9c-48f0-85c3-621cccd58722'::uuid, 2023, 'Paper-I', '______ demonstrates the boundary between shoulders and the pavement.', 'Kerb', 'Drop', 'Drain', 'Wearing coat', 1, 'Kerb separates shoulder from pavement.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'dd2eab18-a6c2-4636-a005-1f9ea9aef419'::uuid, '4002ff85-6eee-4cd3-8c35-1d7039df2745'::uuid, 2023, 'Paper-I', 'If ''v'' is the Poisson''s ratio of material, what is the relationship between modulus of elasticity (E) and shear modulus of elasticity (G)?', 'G = E / (1+ν)', 'G = 2E / (1+ν)', '2G = E / [2(1+ν)]', '2G = E / (1+ν)', 4, 'G = E/[2(1+ν)] => 2G = E/(1+ν).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Le-Chatelier apparatus is used for measuring', 'Pores in the brick', 'Fineness of cement', 'Soundness of cement', 'Specific gravity of cement', 3, 'Le-Chatelier test measures soundness of cement.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a8556419-0986-4502-80b2-78b7defb8990'::uuid, 'ec71764c-6040-47e0-bbc1-9777aafbeec7'::uuid, 2023, 'Paper-I', 'A pitot tube is an instrument for measuring', 'discharge of fluid', 'pressure of flow', 'velocity of flow', 'total energy', 3, 'Pitot tube measures velocity head.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'dd2eab18-a6c2-4636-a005-1f9ea9aef419'::uuid, '4002ff85-6eee-4cd3-8c35-1d7039df2745'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct? A. The rate of change of shear force at any point along the axis of a beam is represented by the load intensity at that point. B. The rate of change of bending moment at any point along the axis of a beam is represented by the load intensity at that point. C. The second order derivative of bending moment at any point along the axis of a beam is represented by the load intensity at that point. D. The rate of change of shear force at any point along the axis of a beam is not represented by the load intensity at that point. Choose the correct option', 'A and C', 'B and D', 'A and B', 'C and D', 1, 'dV/dx = w; d²M/dx² = w. So A and C correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '3f275622-18e3-40ce-a134-ec660b48190c'::uuid, 'f28c858a-cf0c-482e-a112-8845927e82f4'::uuid, 2023, 'Paper-I', 'Match the following instruments with their usage. A. Tellurometer B. Clinometre C. Pantagraph D. Theodolite E. Prism square', 'A-3, B-1, C-5, D-2, E-4', 'A-4, B-3, C-1, D-2, E-5', 'A-1, B-4, C-2, D-3, E-5', 'A-3, B-5, C-4, D-2, E-1', 1, 'Tellurometer - distance (3); Clinometer - slope (1); Pantagraph - map enlargement (5); Theodolite - angles (2); Prism square - right angles (4).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Heavy mortars have a bulk density equal to or greater than', '1000 kg/m³', '500 kg/m³', '1500 kg/m³', '2500 kg/m³', 3, 'Heavy mortars have density ≥ 1500 kg/m³.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Arrange the following steps of production of cement in chronological order: A. blending the materials in the correct proportions B. grinding the clinker and gypsum C. crushing and grinding the raw materials D. burning the prepared mix in a kiln', 'C, A, D, B', 'A, D, B, C', 'A, B, C, D', 'A, C, D, B', 1, 'Crushing → Blending → Burning → Grinding with gypsum.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a8556419-0986-4502-80b2-78b7defb8990'::uuid, 'ec71764c-6040-47e0-bbc1-9777aafbeec7'::uuid, 2023, 'Paper-I', 'The barometer is used to measure', 'Atmospheric pressure', 'Velocity of liquid', 'Pressure in pipes and channels', 'Difference of pressure between two points in a pipe', 1, 'Barometer measures atmospheric pressure.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '3f275622-18e3-40ce-a134-ec660b48190c'::uuid, 'f28c858a-cf0c-482e-a112-8845927e82f4'::uuid, 2023, 'Paper-I', 'The required slope correction for a chain having a length of ''L'' along a slope of θ is', 'L Cos²(θ/2)', '2L Cos²(θ/2)', 'L Sin²(θ/2)', '2L Sin²(θ/2)', 4, 'Slope correction = 2L sin²(θ/2).', 'medium')
